"use client";

import { useState } from "react";
import { DEFAULT_GUARD_KEYWORDS } from "@/types/attendance";
import { useFileUpload } from "@/hooks/useFileUpload";
import { useSheetConfig } from "@/hooks/useSheetConfig";
import { useProcessing } from "@/hooks/useProcessing";
import { useDataTable } from "@/hooks/useDataTable";
import { UploadZone } from "@/components/UploadZone";
import { SheetConfigPanel } from "@/components/SheetConfigPanel";
import { SecurityGuardConfig } from "@/components/SecurityGuardConfig";
import { FilterBar } from "@/components/FilterBar";
import { DataTable } from "@/components/DataTable";
import { Pagination } from "@/components/Pagination";
import { StatsBar } from "@/components/StatsBar";
import { ExportButton } from "@/components/ExportButton";

type Phase = "upload" | "config" | "results";

export default function Home() {
  const { file, workbook, error: uploadError, handleFileChange, reset: resetUpload } =
    useFileUpload();

  const { configs, enabledConfigs, updateConfig, toggleSheet } = useSheetConfig(
    workbook?.sheetNames ?? [],
    workbook?.rawSheets ?? {}
  );

  const [phase, setPhase] = useState<Phase>("upload");
  const [guardKeywords, setGuardKeywords] = useState<string[]>([
    ...DEFAULT_GUARD_KEYWORDS,
  ]);

  const { results, processing, processAll } = useProcessing(
    workbook?.rawSheets ?? {},
    enabledConfigs,
    { checkColumn: 6, keywords: guardKeywords }
  );

  const {
    paginated,
    filters,
    updateFilter,
    pagination,
    goToPage,
    goNext,
    goPrev,
    stats,
    departments,
  } = useDataTable(results);

  const handleProcess = () => {
    processAll();
    setPhase("results");
  };

  const handleReset = () => {
    resetUpload();
    setPhase("upload");
  };

  const hasWorkbook = workbook && workbook.sheetNames.length > 0;

  return (
    <main className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-xl font-bold text-slate-900">
                Attendance OT Calculator
              </h1>
              <p className="text-sm text-slate-500 mt-0.5">
                Multi-shift overtime calculation with security guard exclusion
              </p>
            </div>
            {phase !== "upload" && (
              <button
                onClick={handleReset}
                className="px-4 py-2 text-sm border border-slate-300 rounded-lg text-slate-600 hover:bg-slate-50 transition-colors cursor-pointer"
              >
                Start Over
              </button>
            )}
          </div>
        </div>
      </header>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-8">
        {/* Phase 1: Upload */}
        {phase === "upload" && (
          <div className="max-w-2xl mx-auto">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8">
              <UploadZone
                file={file}
                error={uploadError}
                onFileChange={(e) => {
                  handleFileChange(e);
                  setPhase("config");
                }}
              />

              {hasWorkbook && (
                <div className="mt-6 text-center">
                  <p className="text-sm text-slate-500 mb-3">
                    {workbook.sheetNames.length} sheet(s) detected
                  </p>
                  <button
                    onClick={() => setPhase("config")}
                    className="px-6 py-2.5 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 transition-colors cursor-pointer"
                  >
                    Continue to Configuration
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Phase 2: Configuration */}
        {phase === "config" && hasWorkbook && (
          <div className="space-y-6">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <UploadZone
                file={file}
                error={uploadError}
                onFileChange={handleFileChange}
              />
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <SheetConfigPanel
                configs={configs}
                onUpdateConfig={updateConfig}
                onToggleSheet={toggleSheet}
              />
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
              <SecurityGuardConfig
                keywords={guardKeywords}
                onKeywordsChange={setGuardKeywords}
              />
            </div>

            <div className="flex justify-center pb-4">
              <button
                onClick={handleProcess}
                disabled={processing || enabledConfigs.length === 0}
                className="px-8 py-3 bg-emerald-600 text-white text-base font-semibold rounded-lg hover:bg-emerald-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors cursor-pointer"
              >
                {processing
                  ? "Processing..."
                  : `Process ${enabledConfigs.length} Sheet(s)`}
              </button>
            </div>
          </div>
        )}

        {/* Phase 3: Results */}
        {phase === "results" && (
          <div className="space-y-6">
            {/* Stats */}
            <StatsBar stats={stats} />

            {/* Filters */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
              <div className="flex flex-wrap items-center justify-between gap-4">
                <FilterBar
                  filters={filters}
                  departments={departments}
                  onUpdateFilter={updateFilter}
                />
                <ExportButton data={results} />
              </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
              <DataTable data={paginated} />
              <Pagination
                currentPage={pagination.currentPage}
                totalPages={pagination.totalPages}
                totalRows={stats.totalRows}
                pageSize={pagination.pageSize}
                onPageChange={goToPage}
                onNext={goNext}
                onPrev={goPrev}
              />
            </div>
          </div>
        )}
      </div>
    </main>
  );
}
